async function sbReq(opts) {
  const resp = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers || {}, body: opts.body || undefined });
  const text = await resp.text();
  try { return JSON.parse(text); } catch { return text; }
}

const body = $input.first().json.body;
const timeRange = body.time_range || '1y';
// Country-aware run. Defaults to GENERAL so existing callers without the
// field keep working.
const countryTarget = (body.country_target === 'AU') ? 'AU' : 'GENERAL';
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const sbH = { 'apikey': SRK, 'Authorization': `Bearer ${SRK}`, 'Content-Type': 'application/json' };

// API Key Pool with rotation
const API_KEYS = [
  $env.YOUTUBE_API_KEY,
  $env.YOUTUBE_API_KEY_02,
  $env.YOUTUBE_API_KEY_03,
  $env.YOUTUBE_API_KEY_04,
].filter(Boolean);

const exhaustedKeys = new Set();
let currentKeyIndex = 0;

function getKey() {
  for (let i = 0; i < API_KEYS.length; i++) {
    const idx = (currentKeyIndex + i) % API_KEYS.length;
    if (!exhaustedKeys.has(idx)) return { key: API_KEYS[idx], idx };
  }
  return null;
}

async function ytFetch(url) {
  let attempts = 0;
  while (attempts < API_KEYS.length) {
    const kp = getKey();
    if (!kp) return null;
    const fullUrl = url + (url.includes('?') ? '&' : '?') + `key=${kp.key}`;
    try {
      const resp = await fetch(fullUrl);
      const data = await resp.json();
      if (data.error?.errors?.[0]?.reason === 'quotaExceeded') {
        exhaustedKeys.add(kp.idx);
        currentKeyIndex = (kp.idx + 1) % API_KEYS.length;
        attempts++;
        continue;
      }
      return data;
    } catch { return null; }
  }
  return null;
}

const msMap = { '7d': 604800000, '30d': 2592000000, '90d': 7776000000, '180d': 15552000000, '1y': 31536000000, '2y': 63072000000, '5y': 157680000000 };
const publishedAfter = new Date(Date.now() - (msMap[timeRange] || 31536000000)).toISOString();

const existingIds = new Set();

// General taxonomy (Betrayal, Legal, True Crime) — search the US edition.
const GENERAL_NICHES = [
  // Betrayal & Revenge Stories
  { key: 'betrayals_changed_history', queries: ['betrayals that changed history documentary', 'greatest betrayals in history full', 'historical betrayal documentary full', 'political betrayal documentary', 'famous traitors in history documentary', 'backstabbing that changed the world documentary'] },
  { key: 'family_betrayals_inheritance', queries: ['family betrayal documentary full', 'inheritance war documentary true story', 'family feud true story documentary', 'sibling betrayal documentary full', 'family trust betrayal documentary', 'inheritance dispute documentary full'] },
  { key: 'revenge_stories_gone_wrong', queries: ['revenge gone wrong documentary full', 'revenge story true crime full', 'revenge backfired true story documentary', 'ultimate revenge documentary full', 'revenge plot gone wrong true story', 'when revenge goes too far documentary'] },
  // Legal & Court Drama
  { key: 'shocking_courtroom_moments', queries: ['shocking courtroom moments full video', 'courtroom drama real footage full', 'most dramatic court cases documentary', 'courtroom outburst compilation full', 'judge loses it in court full video', 'wildest courtroom moments documentary'] },
  { key: 'landmark_cases_changed_law', queries: ['landmark court cases documentary full', 'cases that changed the law documentary', 'supreme court landmark decisions full', 'legal cases that made history documentary', 'famous trials documentary full', 'court cases that changed everything documentary'] },
  { key: 'legal_corruption_scandals', queries: ['corrupt lawyer documentary full', 'legal system corruption documentary full', 'wrongful conviction documentary full', 'judicial corruption exposed documentary', 'lawyer scandal true story documentary', 'corrupt judge documentary full'] },
  // True Crime
  { key: 'unsolved_mysteries_cold_cases', queries: ['unsolved mystery documentary full', 'cold case documentary full length', 'FBI unsolved cases documentary full', 'mysterious disappearance documentary full', 'unsolved murders documentary full', 'cold case finally solved documentary full'] },
  { key: 'serial_killers_criminal_profiling', queries: ['serial killer documentary full length', 'criminal profiling documentary full', 'serial killer psychology documentary', 'FBI criminal minds documentary full', 'most dangerous serial killers documentary', 'criminal profiler interview full length'] },
  { key: 'heists_frauds_con_artists', queries: ['greatest heist documentary full', 'con artist documentary full length', 'biggest fraud documentary full', 'bank heist true story documentary', 'ponzi scheme documentary full', 'master thief documentary full length'] },
];

// AU personal-finance taxonomy. Mirrors niche_variants country_target='AU'.
// Queries hand-tuned for Australian English long-form (>=45min) content.
const AU_NICHES = [
  { key: 'credit_cards_au', queries: [
    'australian credit cards points hacking long form',
    'amex platinum australia review long form',
    'qantas frequent flyer points strategy australia long form',
    'velocity points australia full guide',
    'best credit cards australia 2026 review',
    'australian credit card rewards strategy long form',
  ]},
  { key: 'super_au', queries: [
    'australian superannuation explained',
    'self managed super fund SMSF australia',
    'best super fund australia',
    'superannuation comparison australia',
    'super contribution strategy australia',
    'how superannuation works australia',
    'salary sacrifice super australia',
    'australian retirement super planning',
  ]},
  { key: 'property_mortgage_au', queries: [
    'australian property investment',
    'sydney melbourne property market',
    'australian mortgage strategy',
    'first home buyer australia',
    'negative gearing australia',
    'rentvesting australia',
  ]},
  { key: 'tax_au', queries: [
    'australian tax strategy',
    'ATO tax tips australia',
    'australian tax deductions',
    'capital gains tax australia',
    'family trust tax australia',
    'australian small business tax',
  ]},
  { key: 'etf_investing_au', queries: [
    'australian etf investing',
    'ASX etf comparison',
    'VAS VGS VDHG australia',
    'ASX investing for beginners',
    'australian share portfolio',
    'FIRE movement australia',
  ]},
];

// AU finance creators publish 8-25 minute videos with 5k-50k view audiences,
// not US-style 45-min documentaries. The General defaults (videoDuration=long,
// 2700s floor, 50k views floor) returned 0 hits across two 1y AU runs in
// production. Branch the search shape per country.
const SEARCH_PROFILE = countryTarget === 'AU'
  ? { videoDuration: 'medium', minDurationSec: 600,  minViews: 5000  }
  : { videoDuration: 'long',   minDurationSec: 2700, minViews: 50000 };

const ALL_NICHES = countryTarget === 'AU' ? AU_NICHES : GENERAL_NICHES;
const regionCode = countryTarget === 'AU' ? 'AU' : 'US';
const relevanceLanguage = 'en';

// Create run row tagged with country_target.
const run = await sbReq({
  method: 'POST',
  url: `${SB}/rest/v1/yt_discovery_runs`,
  headers: { ...sbH, 'Prefer': 'return=representation' },
  body: JSON.stringify({
    status: 'searching',
    time_range: timeRange,
    country_target: countryTarget,
    started_at: new Date().toISOString(),
  }),
});
const runId = run[0].id;

const selectedNicheKeys = body.niches || ALL_NICHES.map(n => n.key);
const NICHES = ALL_NICHES.filter(n => selectedNicheKeys.includes(n.key));

function parseDuration(iso) {
  if (!iso) return 0;
  const m = iso.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!m) return 0;
  return (parseInt(m[1] || 0) * 3600) + (parseInt(m[2] || 0) * 60) + parseInt(m[3] || 0);
}

const allResults = [];
let allKeysExhausted = false;

for (const niche of NICHES) {
  if (allKeysExhausted) break;

  currentKeyIndex = NICHES.indexOf(niche) % API_KEYS.length;

  const videoMap = new Map();

  for (const query of niche.queries) {
    if (getKey() === null) { allKeysExhausted = true; break; }
    const searchUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(query)}&type=video&videoDuration=${SEARCH_PROFILE.videoDuration}&maxResults=15&order=viewCount&regionCode=${regionCode}&relevanceLanguage=${relevanceLanguage}&publishedAfter=${encodeURIComponent(publishedAfter)}`;
    const resp = await ytFetch(searchUrl);
    if (!resp?.items) continue;
    for (const v of resp.items) {
      const vid = v.id?.videoId;
      if (!vid || videoMap.has(vid) || existingIds.has(vid)) continue;
      videoMap.set(vid, { snippet: v.snippet, videoId: vid });
    }
    await new Promise(r => setTimeout(r, 200));
  }

  if (allKeysExhausted && videoMap.size === 0) break;

  const videoIds = [...videoMap.keys()];
  const videos = [];

  for (let i = 0; i < videoIds.length; i += 50) {
    if (getKey() === null) { allKeysExhausted = true; break; }
    const batch = videoIds.slice(i, i + 50).join(',');
    const detailUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics,contentDetails,snippet&id=${batch}`;
    const detResp = await ytFetch(detailUrl);
    if (!detResp?.items) continue;

    for (const item of detResp.items) {
      const dur = parseDuration(item.contentDetails?.duration);
      if (dur < SEARCH_PROFILE.minDurationSec) continue;
      if (parseInt(item.statistics?.viewCount || 0) < SEARCH_PROFILE.minViews) continue;

      videos.push({
        run_id: runId,
        niche_category: niche.key,
        title: item.snippet?.title || '',
        channel_name: item.snippet?.channelTitle || '',
        published_at: item.snippet?.publishedAt || null,
        views: parseInt(item.statistics?.viewCount || 0),
        likes: parseInt(item.statistics?.likeCount || 0),
        comments: parseInt(item.statistics?.commentCount || 0),
        duration_seconds: dur,
        video_url: `https://youtube.com/watch?v=${item.id}`,
        video_id: item.id,
        thumbnail_url: item.snippet?.thumbnails?.high?.url || item.snippet?.thumbnails?.default?.url || '',
        description: (item.snippet?.description || '').substring(0, 500)
      });
    }
    await new Promise(r => setTimeout(r, 100));
  }

  videos.sort((a, b) => b.views - a.views);
  const top40 = videos.slice(0, 40);

  if (top40.length > 0) {
    for (let i = 0; i < top40.length; i += 20) {
      await sbReq({ method: 'POST', url: `${SB}/rest/v1/yt_discovery_results`, headers: { ...sbH, 'Prefer': 'return=minimal' }, body: JSON.stringify(top40.slice(i, i + 20)) });
    }
    allResults.push(...top40);
    top40.forEach(v => existingIds.add(v.video_id));
  }

  await sbReq({ method: 'PATCH', url: `${SB}/rest/v1/yt_discovery_runs?id=eq.${runId}`, headers: { ...sbH, 'Prefer': 'return=minimal' }, body: JSON.stringify({ total_results: allResults.length }) });
}

const keyReport = API_KEYS.map((_, i) => exhaustedKeys.has(i) ? 'exhausted' : 'ok');
await sbReq({ method: 'PATCH', url: `${SB}/rest/v1/yt_discovery_runs?id=eq.${runId}`, headers: { ...sbH, 'Prefer': 'return=minimal' }, body: JSON.stringify({ status: 'complete', total_results: allResults.length, completed_at: new Date().toISOString(), error_log: allKeysExhausted ? [{ warning: 'Some API keys exhausted', keys: keyReport }] : [] }) });

return [{ json: { run_id: runId, country_target: countryTarget, total_results: allResults.length, keys_used: API_KEYS.length, keys_exhausted: exhaustedKeys.size } }];
